const row = $input.first().json;
const indicators = row.indicators || [];
const prevRegime = row.prev_regime || {};

// Build indicator map
const m = {};
for (const ind of indicators) {
  m[ind.indicator] = { value: parseFloat(ind.value), prev: parseFloat(ind.prev), chg: parseFloat(ind.chg) };
}

// === REGIME CLASSIFICATION ===

// 1. Yield curve spread (10Y - 2Y)
const yieldSpread = m['YIELD_CURVE_SPREAD']?.value ?? (m['US_10Y']?.value && m['US_2Y']?.value ? m['US_10Y'].value - m['US_2Y'].value : null);
const yieldSignal = yieldSpread === null ? 'unknown' : yieldSpread < 0 ? 'inverted' : yieldSpread < 0.5 ? 'flat' : 'normal';

// 2. VIX level
const vix = m['VIX']?.value || m['VIX_RT']?.value || null;
let vixSignal = 'unknown';
if (vix !== null) {
  if (vix < 15) vixSignal = 'complacency';
  else if (vix < 25) vixSignal = 'normal';
  else if (vix < 35) vixSignal = 'fear';
  else vixSignal = 'panic';
}

// 3. DXY trend
const dxy = m['DXY'];
let dxyTrend = 'flat';
if (dxy && dxy.chg !== null) {
  if (dxy.chg > 0.3) dxyTrend = 'rising';
  else if (dxy.chg < -0.3) dxyTrend = 'falling';
}

// 4. CPI (inflation gauge)
const cpi = m['CPI'];
let inflationTrend = 'stable';
if (cpi && cpi.chg !== null) {
  if (cpi.chg > 0.1) inflationTrend = 'rising';
  else if (cpi.chg < -0.1) inflationTrend = 'falling';
}

// 5. Fed phase
const fedRate = m['FED_RATE'];
let fedPhase = 'pausing';
if (fedRate && fedRate.prev !== null) {
  if (fedRate.value > fedRate.prev) fedPhase = 'hiking';
  else if (fedRate.value < fedRate.prev) fedPhase = 'cutting';
}

// 6. SPY trend (growth proxy)
const spy = m['SPY'];
let growthSignal = 'neutral';
if (spy && spy.chg !== null) {
  if (spy.chg > 1) growthSignal = 'strong';
  else if (spy.chg < -1) growthSignal = 'weak';
}

// === MACRO REGIME ===
let macroRegime;
if (inflationTrend === 'rising' && growthSignal !== 'weak') {
  macroRegime = 'inflation_growth';
} else if (inflationTrend === 'rising' && growthSignal === 'weak') {
  macroRegime = 'inflation_stagnation';
} else if (inflationTrend === 'falling' && growthSignal !== 'weak') {
  macroRegime = 'deflation_growth';
} else if (inflationTrend === 'falling' && growthSignal === 'weak') {
  macroRegime = 'deflation_stagnation';
} else {
  macroRegime = 'neutral';
}

// === RISK SENTIMENT ===
let riskSentiment;
if (vixSignal === 'panic' || vixSignal === 'fear') {
  riskSentiment = 'risk_off';
} else if (vixSignal === 'complacency' && dxyTrend === 'falling') {
  riskSentiment = 'risk_on';
} else if (dxyTrend === 'rising' && yieldSignal === 'inverted') {
  riskSentiment = 'risk_off';
} else {
  riskSentiment = 'neutral';
}

// === CONFIDENCE ===
const dataPoints = Object.keys(m).length;
const confidence = Math.min(100, Math.round(dataPoints / 8 * 100));

// === REASONING ===
const reasons = [];
if (vix !== null) reasons.push(`VIX: ${vix.toFixed(1)} (${vixSignal})`);
if (yieldSpread !== null) reasons.push(`Yield spread: ${yieldSpread.toFixed(2)}bp (${yieldSignal})`);
reasons.push(`DXY: ${dxyTrend}`);
reasons.push(`CPI: ${inflationTrend}`);
reasons.push(`Fed: ${fedPhase}`);
reasons.push(`SPY momentum: ${growthSignal}`);
const reasoning = reasons.join('; ');

// === REGIME CHANGE DETECTION ===
const regimeChanged = prevRegime.macro_regime && prevRegime.macro_regime !== macroRegime;
const sentimentChanged = prevRegime.risk_sentiment && prevRegime.risk_sentiment !== riskSentiment;

return [{
  json: {
    macro_regime: macroRegime,
    risk_sentiment: riskSentiment,
    fed_phase: fedPhase,
    yield_curve_spread: yieldSpread,
    vix_level: vix,
    dxy_trend: dxyTrend,
    confidence,
    reasoning,
    regime_changed: regimeChanged || sentimentChanged,
    prev_regime: prevRegime.macro_regime || 'none',
    prev_sentiment: prevRegime.risk_sentiment || 'none',
    timestamp: new Date().toISOString()
  }
}];

